script.String:
APP='spikes/joni-tiptap-collab-demo'; node - <<'NODE'
const fs=require('fs'), cp=require('child_process');
const app=process.env.APP || 'spikes/joni-tiptap-collab-demo';
const out={kind:'joni_tiptap_spike_handoff', app_dir:app, ci_report:'.workflow/joni-tiptap-spike/ci-report.md', review:'.workflow/joni-tiptap-spike/review.md', status:'approved', updated_at:new Date().toISOString()};
try{out.git_status=cp.execSync('git status --short',{encoding:'utf8'}).trim().split('\n').filter(Boolean).slice(0,50)}catch{}
fs.mkdirSync('.workflow/joni-tiptap-spike',{recursive:true});
fs.writeFileSync('.workflow/joni-tiptap-spike/handoff.json', JSON.stringify(out,null,2)+'\n');
console.log(JSON.stringify(out));
NODE

